#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER + 1];
	int  keys [DEFAULT_ORDER + 1];
	int is_leaf;
	int num_keys;
} knode;

__kernel void findK(
		const long maxheight,
		__global const knode *knodes,
		const long knodes_elem,
		__global const record *records,
		__global long *currKnode,
		__global long *offset,
		__global const int *keys,
		__global record *ans)
{
	int bid = get_group_id(0);
	int thid = get_local_id(0);
	int threadsPerBlock = get_local_size(0);

	if (bid >= get_num_groups(0))
		return;

	for (int i = 0; i < maxheight; i++) {
		// Barrier to ensure all local threads synchronization
		barrier(CLK_LOCAL_MEM_FENCE);

		if (thid < threadsPerBlock) {
			int curr_node_idx = currKnode[bid];
			if (curr_node_idx < knodes_elem) {
				int key_th = knodes[curr_node_idx].keys[thid];
				int key_th1 = knodes[curr_node_idx].keys[thid + 1];
				if (key_th <= keys[bid] && key_th1 > keys[bid]) {
					int idx = knodes[offset[bid]].indices[thid];
					if (idx < knodes_elem) {
						offset[bid] = idx;
					}
				}
			}
		}
		// Barrier to ensure offset updated by all threads before next iteration
		barrier(CLK_LOCAL_MEM_FENCE);

		// Update currKnode after all threads finished
		if (thid == 0) {
			currKnode[bid] = offset[bid];
		}
		// Barrier to ensure currKnode updated before next iteration
		barrier(CLK_LOCAL_MEM_FENCE);
	}

	// Final search for equality keys
	if (thid < threadsPerBlock) {
		int curr_node_idx = currKnode[bid];
		if (curr_node_idx < knodes_elem) {
			if (knodes[curr_node_idx].keys[thid] == keys[bid]) {
				int rec_idx = knodes[curr_node_idx].indices[thid];
				ans[bid].value = records[rec_idx].value;
			}
		}
	}
}

