__kernel void findRangeKernel(
		const long maxheight,
		__global const knode *knodes,
		const long knodes_elem,
		const int order,
		const int count,
		__global long *currKnode,
		__global long *offset,
		__global long *lastKnode,
		__global long *offset_2,
		__global const int *start,
		__global const int *end,
		__global int *recstart,
		__global int *reclength)
{
	int bid = get_group_id(0);
	int thid = get_local_id(0);
	int threadsPerBlock = get_local_size(0);

	if (bid >= count)
		return;

	for (int i = 0; i < maxheight; i++) {
		barrier(CLK_LOCAL_MEM_FENCE);

		if (thid < threadsPerBlock) {
			int curr_node_idx = currKnode[bid];
			int last_node_idx = lastKnode[bid];

			if (curr_node_idx < knodes_elem) {
				int key_curr_th = knodes[curr_node_idx].keys[thid];
				int key_curr_th1 = knodes[curr_node_idx].keys[thid + 1];
				if (key_curr_th <= start[bid] && key_curr_th1 > start[bid]) {
					int idx = knodes[curr_node_idx].indices[thid];
					if (idx < knodes_elem) {
						offset[bid] = idx;
					}
				}
			}

			if (last_node_idx < knodes_elem) {
				int key_last_th = knodes[last_node_idx].keys[thid];
				int key_last_th1 = knodes[last_node_idx].keys[thid + 1];
				if (key_last_th <= end[bid] && key_last_th1 > end[bid]) {
					int idx2 = knodes[last_node_idx].indices[thid];
					if (idx2 < knodes_elem) {
						offset_2[bid] = idx2;
					}
				}
			}
		}

		barrier(CLK_LOCAL_MEM_FENCE);

		if (thid == 0) {
			currKnode[bid] = offset[bid];
			lastKnode[bid] = offset_2[bid];
		}

		barrier(CLK_LOCAL_MEM_FENCE);
	}

	// Final step for recstart
	if (thid < threadsPerBlock) {
		int curr_node_idx = currKnode[bid];
		if (curr_node_idx < knodes_elem) {
			if (knodes[curr_node_idx].keys[thid] == start[bid]) {
				recstart[bid] = knodes[curr_node_idx].indices[thid];
			}
		}
	}

	// Final step for reclength
	if (thid < threadsPerBlock) {
		int last_node_idx = lastKnode[bid];
		if (last_node_idx < knodes_elem) {
			if (knodes[last_node_idx].keys[thid] == end[bid]) {
				reclength[bid] = knodes[last_node_idx].indices[thid] - recstart[bid] + 1;
			}
		}
	}
}
